import{_ as t,o,c as a,a2 as i}from"./chunks/framework.B8zgMDLd.js";const p=JSON.parse('{"title":"Use The AI","description":"","frontmatter":{},"headers":[],"relativePath":"guides/use-ai-panel.md","filePath":"guides/use-ai-panel.md"}'),r={name:"guides/use-ai-panel.md"};function s(n,e,l,h,d,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="use-the-ai" tabindex="-1">Use The AI <a class="header-anchor" href="#use-the-ai" aria-label="Permalink to &quot;Use The AI&quot;">​</a></h1><p>Tolaria gives you two ways to ask for AI help: open the AI panel for an ongoing conversation, or prompt directly from the editor with <code>Cmd+K</code> followed by a space.</p><h2 id="choose-how-to-prompt" tabindex="-1">Choose How To Prompt <a class="header-anchor" href="#choose-how-to-prompt" aria-label="Permalink to &quot;Choose How To Prompt&quot;">​</a></h2><ul><li><strong>AI panel</strong> is best for longer conversations, agent work, and requests that need visible back-and-forth.</li><li><strong>Inline prompt</strong> is best when you are already writing. Press <code>Cmd+K</code>, type a space, then write the prompt you want the AI to handle from the current note context.</li></ul><h2 id="choose-a-target" tabindex="-1">Choose A Target <a class="header-anchor" href="#choose-a-target" aria-label="Permalink to &quot;Choose A Target&quot;">​</a></h2><p>Open Settings and choose the default AI target:</p><ul><li><strong>Coding agent</strong> for tool-backed vault editing through Claude Code, Codex, OpenCode, Pi, or Gemini CLI.</li><li><strong>Local model</strong> for Ollama or LM Studio chat over note context.</li><li><strong>API model</strong> for OpenAI, Anthropic, Gemini, OpenRouter, or an OpenAI-compatible endpoint.</li></ul><p>If a coding agent is missing, install it and reopen Tolaria or switch to another target.</p><h2 id="permission-mode" tabindex="-1">Permission Mode <a class="header-anchor" href="#permission-mode" aria-label="Permalink to &quot;Permission Mode&quot;">​</a></h2><p>Coding agents support per-vault permission modes:</p><ul><li><strong>Vault Safe</strong> keeps agents limited to file, search, and edit tools.</li><li><strong>Power User</strong> can allow shell commands for agents that support them.</li></ul><p>Direct model targets always stay in chat mode. They can use note context, but they cannot edit vault files through tools.</p><h2 id="good-requests" tabindex="-1">Good Requests <a class="header-anchor" href="#good-requests" aria-label="Permalink to &quot;Good Requests&quot;">​</a></h2><ul><li>&quot;Find notes related to this project.&quot;</li><li>&quot;Summarize what changed in this note.&quot;</li><li>&quot;Draft a weekly review from these linked notes.&quot;</li><li>&quot;Update this checklist based on the current project status.&quot;</li></ul><h2 id="review-changes" tabindex="-1">Review Changes <a class="header-anchor" href="#review-changes" aria-label="Permalink to &quot;Review Changes&quot;">​</a></h2><p>AI edits are file edits. Review them with Tolaria&#39;s diff and Git history before committing.</p>',16)])])}const m=t(r,[["render",s]]);export{p as __pageData,m as default};
